{
    "level": "A1–A2",
    "intro": "У минулому часі дієслово <strong>to be</strong> має форми <strong>was / were</strong>. Вони потрібні, коли ти говориш, <strong>яким хтось був</strong>, <strong>де хтось був</strong> або <strong>що було правдою раніше</strong>.",
    "rules": [
        {
            "label": "was",
            "color": "emerald",
            "text": "З <strong>I / he / she / it</strong> вживай <strong>was</strong>.",
            "example": "I was tired. / She was at home."
        },
        {
            "label": "were",
            "color": "blue",
            "text": "З <strong>you / we / they</strong> вживай <strong>were</strong>.",
            "example": "You were right. / They were late."
        },
        {
            "label": "Питання без did",
            "color": "amber",
            "text": "У питаннях з <strong>to be</strong> не потрібне <strong>did</strong>.",
            "example": "Was he busy? / Were they ready?"
        }
    ]
}

{
    "title": "1. Форми was / were",
    "intro": "Почни з двох головних форм і швидко запам'ятай, з ким вони йдуть.",
    "items": [
        {
            "label": "I / He / She / It",
            "title": "was",
            "subtitle": "I was happy. / It was cold."
        },
        {
            "label": "You / We / They",
            "title": "were",
            "subtitle": "You were late. / They were happy."
        },
        {
            "label": "Заперечення",
            "title": "was not / were not",
            "subtitle": "wasn't / weren't — це короткі форми."
        },
        {
            "label": "Схема",
            "title": "Subject + was / were",
            "subtitle": "She was at home. / We were ready."
        }
    ]
}

{
    "title": "2. Заперечення",
    "intro": "Щоб зробити заперечення, додай <strong>not</strong> після <strong>was / were</strong>.",
    "rows": [
        {
            "en": "I was at home.",
            "ua": "I wasn't at home.",
            "note": "wasn't = was not"
        },
        {
            "en": "She was tired.",
            "ua": "She was not tired.",
            "note": "Повна форма звучить чіткіше."
        },
        {
            "en": "They were late.",
            "ua": "They weren't late.",
            "note": "weren't = were not"
        }
    ],
    "warning": "📌 З <strong>to be</strong> у минулому не додавай <strong>didn't</strong>."
}

{
    "title": "3. Питання",
    "sections": [
        {
            "label": "Was + I / he / she / it",
            "color": "emerald",
            "description": "З <strong>I / he / she / it</strong> починай питання з <strong>was</strong>.",
            "examples": [
                {
                    "en": "Was he at work yesterday?",
                    "ua": "Чи був він учора на роботі?"
                },
                {
                    "en": "Was it difficult?",
                    "ua": "Чи було це складно?"
                }
            ]
        },
        {
            "label": "Were + you / we / they",
            "color": "blue",
            "description": "З <strong>you / we / they</strong> став <strong>were</strong> перед підметом.",
            "examples": [
                {
                    "en": "Were you busy?",
                    "ua": "Ти був зайнятий?"
                },
                {
                    "en": "Were they ready?",
                    "ua": "Вони були готові?"
                }
            ]
        },
        {
            "label": "Без did",
            "color": "amber",
            "description": "З <strong>to be</strong> ми просто робимо інверсію: <strong>was / were + subject</strong>.",
            "examples": [
                {
                    "en": "She was at home. → Was she at home?",
                    "ua": "Ствердження перетворюється на питання без did."
                },
                {
                    "en": "Where were you yesterday?",
                    "ua": "У питанні з питальним словом після нього також іде was / were."
                }
            ]
        }
    ]
}

{
    "title": "4. Короткі відповіді",
    "intro": "У короткій відповіді повтори <strong>was</strong> або <strong>were</strong>.",
    "rows": [
        {
            "en": "Were you at home?",
            "ua": "Yes, I was. / No, I wasn't.",
            "note": "У відповіді на Were you...? кажемо I was / I wasn't."
        },
        {
            "en": "Was she ready?",
            "ua": "Yes, she was. / No, she wasn't.",
            "note": "was → she was / she wasn't"
        },
        {
            "en": "Were they late?",
            "ua": "Yes, they were. / No, they weren't.",
            "note": "were → they were / they weren't"
        }
    ],
    "warning": "📌 Коротка відповідь бере <strong>was / were</strong>, а не <strong>did</strong>."
}

{
    "title": "5. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Плутати was і were.",
            "wrong": "❌ They was late.",
            "right": "✅ <span class=\"font-mono\">They were late.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Додавати did до to be.",
            "wrong": "❌ Did she was at home?",
            "right": "✅ <span class=\"font-mono\">Was she at home?</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Давати неправильну коротку відповідь.",
            "wrong": "❌ Yes, they was.",
            "right": "✅ <span class=\"font-mono\">Yes, they were.</span>"
        }
    ]
}

